from fastapi import FastAPI

app = FastAPI()

courses = [
    {"id": 1, "name": "Python Basic", "level": "beginner", "price": 1500000},
    {"id": 2, "name": "Web API with FastAPI", "level": "intermediate", "price": 2500000},
]

@app.get("/courses")
def search_courses(keyword: str = "", level: str | None = None):
    result = courses
    if keyword:
        result = [c for c in result if keyword.lower() in c["name"].lower()]
    if level:
        result = [c for c in result if c["level"] == level]
    return result

from fastapi import FastAPI
